2	/*
3	 * Copyright (C) Igor Sysoev
4	 * Copyright (C) Nginx, Inc.
5	 */
6	
7	
8	#include <ngx_config.h>
9	#include <ngx_core.h>
10	
11	
12	static ngx_msec_t ngx_monotonic_time(time_t sec, ngx_uint_t msec);
13	
14	
15	/*
16	 * The time may be updated by signal handler or by several threads.
17	 * The time update operations are rare and require to hold the ngx_time_lock.
18	 * The time read operations are frequent, so they are lock-free and get time
19	 * values and strings from the current slot.  Thus thread may get the corrupted
20	 * values only if it is preempted while copying and then it is not scheduled
21	 * to run more than NGX_TIME_SLOTS seconds.
22	 */
23	
24	#define NGX_TIME_SLOTS   64
25	
26	static ngx_uint_t        slot;
27	static ngx_atomic_t      ngx_time_lock;
28	
29	volatile ngx_msec_t      ngx_current_msec;
30	volatile ngx_time_t     *ngx_cached_time;
31	volatile ngx_str_t       ngx_cached_err_log_time;
32	volatile ngx_str_t       ngx_cached_http_time;
33	volatile ngx_str_t       ngx_cached_http_log_time;
34	volatile ngx_str_t       ngx_cached_http_log_iso8601;
35	volatile ngx_str_t       ngx_cached_syslog_time;
36	
37	#if !(NGX_WIN32)
38	
39	/*
40	 * localtime() and localtime_r() are not Async-Signal-Safe functions, therefore,
41	 * they must not be called by a signal handler, so we use the cached
42	 * GMT offset value. Fortunately the value is changed only two times a year.
43	 */
44	
45	static ngx_int_t         cached_gmtoff;
46	#endif
47	
48	static ngx_time_t        cached_time[NGX_TIME_SLOTS];
49	static u_char            cached_err_log_time[NGX_TIME_SLOTS]
50	                                    [sizeof("1970/09/28 12:00:00")];
51	static u_char            cached_http_time[NGX_TIME_SLOTS]
52	                                    [sizeof("Mon, 28 Sep 1970 06:00:00 GMT")];
53	static u_char            cached_http_log_time[NGX_TIME_SLOTS]
54	                                    [sizeof("28/Sep/1970:12:00:00 +0600")];
55	static u_char            cached_http_log_iso8601[NGX_TIME_SLOTS]
56	                                    [sizeof("1970-09-28T12:00:00+06:00")];
57	static u_char            cached_syslog_time[NGX_TIME_SLOTS]
58	                                    [sizeof("Sep 28 12:00:00")];
59	
60	
61	static char  *week[] = { "Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat" };
62	static char  *months[] = { "Jan", "Feb", "Mar", "Apr", "May", "Jun",
63	                           "Jul", "Aug", "Sep", "Oct", "Nov", "Dec" };
64	
65	void
66	ngx_time_init(void)
67	{
68	    ngx_cached_err_log_time.len = sizeof("1970/09/28 12:00:00") - 1;
69	    ngx_cached_http_time.len = sizeof("Mon, 28 Sep 1970 06:00:00 GMT") - 1;
70	    ngx_cached_http_log_time.len = sizeof("28/Sep/1970:12:00:00 +0600") - 1;
71	    ngx_cached_http_log_iso8601.len = sizeof("1970-09-28T12:00:00+06:00") - 1;
72	    ngx_cached_syslog_time.len = sizeof("Sep 28 12:00:00") - 1;
73	
74	    ngx_cached_time = &cached_time[0];
75	
76	    ngx_time_update();
77	}
78	
79	
80	void
81	ngx_time_update(void)
82	{
83	    u_char          *p0, *p1, *p2, *p3, *p4;
84	    ngx_tm_t         tm, gmt;
85	    time_t           sec;
86	    ngx_uint_t       msec;
87	    ngx_time_t      *tp;
88	    struct timeval   tv;
89	
90	    if (!ngx_trylock(&ngx_time_lock)) {
91	        return;
92	    }
93	
94	    ngx_gettimeofday(&tv);
95	
96	    sec = tv.tv_sec;
97	    msec = tv.tv_usec / 1000;
98	
99	    ngx_current_msec = ngx_monotonic_time(sec, msec);
100	
101	    tp = &cached_time[slot];
102	
103	    if (tp->sec == sec) {
104	        tp->msec = msec;
105	        ngx_unlock(&ngx_time_lock);
106	        return;
107	    }
108	
109	    if (slot == NGX_TIME_SLOTS - 1) {
110	        slot = 0;
111	    } else {
112	        slot++;
113	    }
114	
115	    tp = &cached_time[slot];
116	
117	    tp->sec = sec;
118	    tp->msec = msec;
119	
120	    ngx_gmtime(sec, &gmt);
121	
122	
123	    p0 = &cached_http_time[slot][0];
124	
125	    (void) ngx_sprintf(p0, "%s, %02d %s %4d %02d:%02d:%02d GMT",
126	                       week[gmt.ngx_tm_wday], gmt.ngx_tm_mday,
127	                       months[gmt.ngx_tm_mon - 1], gmt.ngx_tm_year,
128	                       gmt.ngx_tm_hour, gmt.ngx_tm_min, gmt.ngx_tm_sec);
129	
130	#if (NGX_HAVE_GETTIMEZONE)
131	
132	    tp->gmtoff = ngx_gettimezone();
133	    ngx_gmtime(sec + tp->gmtoff * 60, &tm);
134	
135	#elif (NGX_HAVE_GMTOFF)
136	
137	    ngx_localtime(sec, &tm);
138	    cached_gmtoff = (ngx_int_t) (tm.ngx_tm_gmtoff / 60);
139	    tp->gmtoff = cached_gmtoff;
140	
141	#else
142	
143	    ngx_localtime(sec, &tm);
144	    cached_gmtoff = ngx_timezone(tm.ngx_tm_isdst);
145	    tp->gmtoff = cached_gmtoff;
146	
147	#endif
148	
149	
150	    p1 = &cached_err_log_time[slot][0];
151	
152	    (void) ngx_sprintf(p1, "%4d/%02d/%02d %02d:%02d:%02d",
153	                       tm.ngx_tm_year, tm.ngx_tm_mon,
154	                       tm.ngx_tm_mday, tm.ngx_tm_hour,
155	                       tm.ngx_tm_min, tm.ngx_tm_sec);
156	
157	
158	    p2 = &cached_http_log_time[slot][0];
159	
160	    (void) ngx_sprintf(p2, "%02d/%s/%d:%02d:%02d:%02d %c%02i%02i",
161	                       tm.ngx_tm_mday, months[tm.ngx_tm_mon - 1],
162	                       tm.ngx_tm_year, tm.ngx_tm_hour,
163	                       tm.ngx_tm_min, tm.ngx_tm_sec,
164	                       tp->gmtoff < 0 ? '-' : '+',
165	                       ngx_abs(tp->gmtoff / 60), ngx_abs(tp->gmtoff % 60));
166	
167	    p3 = &cached_http_log_iso8601[slot][0];
168	
169	    (void) ngx_sprintf(p3, "%4d-%02d-%02dT%02d:%02d:%02d%c%02i:%02i",
170	                       tm.ngx_tm_year, tm.ngx_tm_mon,
171	                       tm.ngx_tm_mday, tm.ngx_tm_hour,
172	                       tm.ngx_tm_min, tm.ngx_tm_sec,
173	                       tp->gmtoff < 0 ? '-' : '+',
174	                       ngx_abs(tp->gmtoff / 60), ngx_abs(tp->gmtoff % 60));
175	
176	    p4 = &cached_syslog_time[slot][0];
177	
178	    (void) ngx_sprintf(p4, "%s %2d %02d:%02d:%02d",
179	                       months[tm.ngx_tm_mon - 1], tm.ngx_tm_mday,
180	                       tm.ngx_tm_hour, tm.ngx_tm_min, tm.ngx_tm_sec);
181	
182	    ngx_memory_barrier();
183	
184	    ngx_cached_time = tp;
185	    ngx_cached_http_time.data = p0;
186	    ngx_cached_err_log_time.data = p1;
187	    ngx_cached_http_log_time.data = p2;
188	    ngx_cached_http_log_iso8601.data = p3;
189	    ngx_cached_syslog_time.data = p4;
190	
191	    ngx_unlock(&ngx_time_lock);
192	}
193	
194	
195	static ngx_msec_t
196	ngx_monotonic_time(time_t sec, ngx_uint_t msec)
197	{
198	#if (NGX_HAVE_CLOCK_MONOTONIC)
199	    struct timespec  ts;
200	
201	    clock_gettime(CLOCK_MONOTONIC, &ts);
202	
203	    sec = ts.tv_sec;
204	    msec = ts.tv_nsec / 1000000;
205	
206	#endif
207	
208	    return (ngx_msec_t) sec * 1000 + msec;
209	}
210	
211	
212	#if !(NGX_WIN32)
213	
214	void
215	ngx_time_sigsafe_update(void)
216	{
217	    u_char          *p, *p2;
218	    ngx_tm_t         tm;
219	    time_t           sec;
220	    ngx_time_t      *tp;
221	    struct timeval   tv;
222	
223	    if (!ngx_trylock(&ngx_time_lock)) {
224	        return;
225	    }
226	
227	    ngx_gettimeofday(&tv);
228	
229	    sec = tv.tv_sec;
230	
231	    tp = &cached_time[slot];
232	
233	    if (tp->sec == sec) {
234	        ngx_unlock(&ngx_time_lock);
235	        return;
236	    }
237	
238	    if (slot == NGX_TIME_SLOTS - 1) {
239	        slot = 0;
240	    } else {
241	        slot++;
242	    }
243	
244	    tp = &cached_time[slot];
245	
246	    tp->sec = 0;
247	
248	    ngx_gmtime(sec + cached_gmtoff * 60, &tm);
249	
250	    p = &cached_err_log_time[slot][0];
251	
252	    (void) ngx_sprintf(p, "%4d/%02d/%02d %02d:%02d:%02d",
253	                       tm.ngx_tm_year, tm.ngx_tm_mon,
254	                       tm.ngx_tm_mday, tm.ngx_tm_hour,
255	                       tm.ngx_tm_min, tm.ngx_tm_sec);
256	
257	    p2 = &cached_syslog_time[slot][0];
258	
259	    (void) ngx_sprintf(p2, "%s %2d %02d:%02d:%02d",
260	                       months[tm.ngx_tm_mon - 1], tm.ngx_tm_mday,
261	                       tm.ngx_tm_hour, tm.ngx_tm_min, tm.ngx_tm_sec);
262	
263	    ngx_memory_barrier();
264	
265	    ngx_cached_err_log_time.data = p;
266	    ngx_cached_syslog_time.data = p2;
267	
268	    ngx_unlock(&ngx_time_lock);
269	}
270	
271	#endif
272	
273	
274	u_char *
275	ngx_http_time(u_char *buf, time_t t)
276	{
277	    ngx_tm_t  tm;
278	
279	    ngx_gmtime(t, &tm);
280	
281	    return ngx_sprintf(buf, "%s, %02d %s %4d %02d:%02d:%02d GMT",
282	                       week[tm.ngx_tm_wday],
283	                       tm.ngx_tm_mday,
284	                       months[tm.ngx_tm_mon - 1],
285	                       tm.ngx_tm_year,
286	                       tm.ngx_tm_hour,
287	                       tm.ngx_tm_min,
288	                       tm.ngx_tm_sec);
289	}
290	
291	
292	u_char *
293	ngx_http_cookie_time(u_char *buf, time_t t)
294	{
295	    ngx_tm_t  tm;
296	
297	    ngx_gmtime(t, &tm);
298	
299	    /*
300	     * Netscape 3.x does not understand 4-digit years at all and
301	     * 2-digit years more than "37"
302	     */
303	
304	    return ngx_sprintf(buf,
305	                       (tm.ngx_tm_year > 2037) ?
306	                                         "%s, %02d-%s-%d %02d:%02d:%02d GMT":
307	                                         "%s, %02d-%s-%02d %02d:%02d:%02d GMT",
308	                       week[tm.ngx_tm_wday],
309	                       tm.ngx_tm_mday,
310	                       months[tm.ngx_tm_mon - 1],
311	                       (tm.ngx_tm_year > 2037) ? tm.ngx_tm_year:
312	                                                 tm.ngx_tm_year % 100,
313	                       tm.ngx_tm_hour,
314	                       tm.ngx_tm_min,
315	                       tm.ngx_tm_sec);
316	}
317	
318	
319	void
320	ngx_gmtime(time_t t, ngx_tm_t *tp)
321	{
322	    ngx_int_t   yday;
323	    ngx_uint_t  sec, min, hour, mday, mon, year, wday, days, leap;
324	
325	    /* the calculation is valid for positive time_t only */
326	
327	    if (t < 0) {
328	        t = 0;
329	    }
330	
331	    days = t / 86400;
332	    sec = t % 86400;
333	
334	    /*
335	     * no more than 4 year digits supported,
336	     * truncate to December 31, 9999, 23:59:59
337	     */
338	
339	    if (days > 2932896) {
340	        days = 2932896;
341	        sec = 86399;
342	    }
343	
344	    /* January 1, 1970 was Thursday */
345	
346	    wday = (4 + days) % 7;
347	
348	    hour = sec / 3600;
349	    sec %= 3600;
350	    min = sec / 60;
351	    sec %= 60;
352	
353	    /*
354	     * the algorithm based on Gauss' formula,
355	     * see src/core/ngx_parse_time.c
356	     */
357	
358	    /* days since March 1, 1 BC */
359	    days = days - (31 + 28) + 719527;
360	
361	    /*
362	     * The "days" should be adjusted to 1 only, however, some March 1st's go
363	     * to previous year, so we adjust them to 2.  This causes also shift of the
364	     * last February days to next year, but we catch the case when "yday"
365	     * becomes negative.
366	     */
367	
368	    year = (days + 2) * 400 / (365 * 400 + 100 - 4 + 1);
369	
370	    yday = days - (365 * year + year / 4 - year / 100 + year / 400);
371	
372	    if (yday < 0) {
373	        leap = (year % 4 == 0) && (year % 100 || (year % 400 == 0));
374	        yday = 365 + leap + yday;
375	        year--;
376	    }
377	
378	    /*
379	     * The empirical formula that maps "yday" to month.
380	     * There are at least 10 variants, some of them are:
381	     *     mon = (yday + 31) * 15 / 459
382	     *     mon = (yday + 31) * 17 / 520
383	     *     mon = (yday + 31) * 20 / 612
384	     */
385	
386	    mon = (yday + 31) * 10 / 306;
387	
388	    /* the Gauss' formula that evaluates days before the month */
389	
390	    mday = yday - (367 * mon / 12 - 30) + 1;
391	
392	    if (yday >= 306) {
393	
394	        year++;
395	        mon -= 10;
396	
397	        /*
398	         * there is no "yday" in Win32 SYSTEMTIME
399	         *
400	         * yday -= 306;
401	         */
402	
403	    } else {
404	
405	        mon += 2;
406	
407	        /*
408	         * there is no "yday" in Win32 SYSTEMTIME
409	         *
410	         * yday += 31 + 28 + leap;
411	         */
412	    }
413	
414	    tp->ngx_tm_sec = (ngx_tm_sec_t) sec;
415	    tp->ngx_tm_min = (ngx_tm_min_t) min;
416	    tp->ngx_tm_hour = (ngx_tm_hour_t) hour;
417	    tp->ngx_tm_mday = (ngx_tm_mday_t) mday;
418	    tp->ngx_tm_mon = (ngx_tm_mon_t) mon;
419	    tp->ngx_tm_year = (ngx_tm_year_t) year;
420	    tp->ngx_tm_wday = (ngx_tm_wday_t) wday;
421	}
422	
423	
424	time_t
425	ngx_next_time(time_t when)
426	{
427	    time_t     now, next;
428	    struct tm  tm;
429	
430	    now = ngx_time();
431	
432	    ngx_libc_localtime(now, &tm);
433	
434	    tm.tm_hour = (int) (when / 3600);
435	    when %= 3600;
436	    tm.tm_min = (int) (when / 60);
437	    tm.tm_sec = (int) (when % 60);
438	
439	    next = mktime(&tm);
440	
441	    if (next == -1) {
442	        return -1;
443	    }
444	
445	    if (next - now > 0) {
446	        return next;
447	    }
448	
449	    tm.tm_mday++;
450	
451	    /* mktime() should normalize a date (Jan 32, etc) */
452	
453	    next = mktime(&tm);
454	
455	    if (next != -1) {
456	        return next;
457	    }
458	
459	    return -1;
460	}
